INSERT INTO reviews (id, nickname, rating, title, comment, created_at, approved) VALUES
('rev-001', '簿記初学者うさぎ', 5, '参考書より圧倒的にわかりやすい', '現役税理士監修というだけあって解説が非常に丁寧です。分厚い参考書を読んでも理解できなかった仕訳のルールが、このアプリの解説文で一瞬で腑に落ちました。', '2026-06-15T09:12:00Z', 1),
('rev-002', 'タクミ', 5, '耳学ラジオが通勤で神すぎる', '通勤電車の満員の中でも、耳学モード（音声ラジオ）で効率的にインプットができます。画面を見ずに仕訳のルールが頭に入ってくるので重宝しています。', '2026-06-16T18:45:00Z', 1),
('rev-003', 'Nexusファン', 5, '買い切り500円は破格', 'サブスクで毎月課金される学習アプリが多い中、ワンコイン500円で買い切り（一生使い放題）は本当に良心的。アプリのクオリティからして安すぎます！', '2026-06-18T12:00:00Z', 1),
('rev-004', '現役受験生', 4, 'スマホでの大問UIが優秀', 'スマホで大問対策は難しいと思っていましたが、このアプリの2カラムUIは凄く解きやすいです。スクロールがスムーズでストレスなく本試験の過去問演習ができます。', '2026-06-19T21:30:00Z', 1),
('rev-005', 'マナミ', 5, 'うさぴょん達が可愛い！', 'キャラクターたちのリアクションが可愛くて、勉強というよりゲーム感覚で楽しく続けられています。モチベーション維持に最適です。', '2026-06-20T15:10:00Z', 1),
('rev-006', '30代会社員', 4, '隙間時間に最適', '1回5分の仕訳練習で、毎日の積み重ねができています。忙しい社会人にぴったりの学習ツールですね。おかげで勉強の習慣がつきました。', '2026-06-22T08:05:00Z', 1),
('rev-007', 'ケンジ', 5, '模擬試験モードで合格ライン突破！', '本試験と同じ60分タイマーで実践的な模擬試験ができるのが良い。AI採点と苦手分析のおかげで、第2問の帳簿記入を克服できました！', '2026-06-24T14:20:00Z', 1),
('rev-008', '主婦受験生', 5, '家事の合間に耳学', '家事をしながらワイヤレスイヤホンで耳学ラジオを聞いています。仕訳の基礎知識が自然に刷り込まれていき、机に向かう時間が少なくても理解が進みます。', '2026-06-25T11:40:00Z', 1),
('rev-009', 'ユウキ', 4, 'Web版も便利です', 'スマホとWeb版両方使っていますが、家ではPCの大きな画面で大問を解き、外出先ではスマホで仕訳をする使い分けができて便利です。ドメインが変わってアクセスも良くなりました！', '2026-06-27T19:15:00Z', 1),
('rev-010', '簿記の壁越え隊', 5, '解説のアプローチが抜群', '勘定科目の増減の考え方がすごくロジカルに解説されています。「なぜ借方にこれがくるのか」が納得できるので、暗記に頼らず応用力がつきます。', '2026-06-28T22:05:00Z', 1),
('rev-011', '商学部1年', 4, '授業の予習復習に', '大学の簿記の講義が難しくて置いていかれそうでしたが、このアプリで予習することで理解度が劇的に上がりました。仕訳演習の数が豊富で助かります。', '2026-06-29T17:30:00Z', 1),
('rev-012', 'キャリアアップ志向', 5, '挫折続きだった私でも', '以前、参考書を買って3日で挫折しましたが、ボキまる先生は現在2週間毎日続けられています！キャラクターが褒めてくれるのが地味に励みになります。', '2026-06-30T23:50:00Z', 1),
('rev-013', 'リョウタ', 5, '税理士監修の信頼感', '問題の質が本試験に近く、解説も税理士事務所ならではの実務的なニュアンスが含まれていて勉強になります。これだけのボリュームで500円は素晴らしい。', '2026-07-01T07:15:00Z', 1),
('rev-014', '匿名リスナー', 4, 'ラジオ講義が聴きやすい', '耳学ラジオの解説者の声が聞き取りやすく、テンポも良い。散歩やジョギング中の新しい勉強スタイルとして定着しました。', '2026-07-01T16:00:00Z', 1),
('rev-015', '合格目指すママ', 5, '子供が寝たあとにコツコツ', '深夜に机を広げて電卓を叩くのは大変ですが、ベッドの中でスマホ1台で模擬試験まで完結できるのは本当に助かります。音量調整ボタンがあるのも親切！', '2026-07-02T13:25:00Z', 1),
('rev-016', 'タカヒロ', 4, 'AI分析が鋭い', '自分が何度も間違える「前払費用」などの決算整理仕訳をAIが自動で検知し、集中的に出題してくれます。効率よく弱点補強ができました。', '2026-07-02T20:10:00Z', 1),
('rev-017', '簿記3級リベンジ', 5, '前回の不合格からこれで合格！', '一度独学で落ちて諦めていましたが、このアプリに出会って再挑戦。大問の解き方のコツがアプリで分かり、見事リベンジ合格しました！本当に感謝しています。', '2026-07-03T09:40:00Z', 1),
('rev-018', 'サクラサク', 5, '超おすすめアプリ', 'ネットのレビューを見て半信半疑で購入しましたが、本当に仕訳がサクサク頭に入ります。AIのアドバイス通りに進めるだけで自然と力がつきます。', '2026-07-03T18:12:00Z', 1),
('rev-019', '経理事務員', 5, '実務の復習にもなる', '実務で経理をしていますが、基礎の確認用に購入。仕訳の網羅性が高く、初学者はもちろん、ブランクがある人の学び直しにも非常に有用だと思います。', '2026-07-04T12:05:00Z', 1),
('rev-020', '学生A', 3, '問題が少し難しめかも？', '初心者の私には、模擬試験の第3問が少し難しく感じました。でも、仕訳対策を何度も繰り返すうちにだんだん解けるようになってきました。解説をしっかり読むのがコツです。', '2026-07-04T15:40:00Z', 1),
('rev-021', 'コウジ', 5, 'Web版との連携が快適', '新しい独自ドメインでのWeb版、非常に軽快に動きますね。画面のレイアウトもスマホ版と同じ没入感があり、自宅ではPCでガッツリ解いています！', '2026-07-05T10:20:00Z', 1),
('rev-022', 'ミサキ', 5, '神アプリ決定です', '現役の税理士さんが作ったからか、問題のクオリティが抜群に高い。試験直前の対策にこれを買ったのですが、よく出るパターンの仕訳が網羅されていて助かりました。', '2026-07-05T14:55:00Z', 1),
('rev-023', 'シホ', 4, '楽しいし挫折しない', 'キャラクターのホー先生の解説が大好きです。仕訳が間違っていても優しく励ましてくれるので嫌になりません。試験対応もしっかりしていて頼もしい。', '2026-07-05T20:30:00Z', 1),
('rev-024', 'サラリーマン学習者', 5, 'コスパ最強のツール', '500円でこれだけの内容とAIサポートが受けられるのはコスパが良すぎます。Webとスマホどちらでも同じ進行度で学べるのもうれしい。', '2026-07-06T08:15:00Z', 1),
('rev-025', 'トモヤ', 5, '模擬試験のAI採点が速い', '模擬試験モードを解き終わった瞬間、AIが瞬時に採点して詳細なレポートを出してくれます。どこで減点されたかがすぐ分かるので、復習がとてもスムーズです。', '2026-07-06T13:40:00Z', 1),
('rev-026', 'ハルカ', 4, '耳学モードのおかげ', '家事中に仕訳の「耳学ラジオ」を毎日流していました。用語の響きに慣れたことで、問題を解くときのスピードが格段に早くなりました。', '2026-07-06T19:00:00Z', 1),
('rev-027', '独学で合格', 5, 'このアプリだけでいけた！', 'テキスト等は一切買わず、このアプリの仕訳310問と模擬試験だけで簿記3級に合格できました！出題範囲の変更にもしっかり対応していて安心です。', '2026-07-07T11:10:00Z', 1),
('rev-028', '経理のひよこ', 4, '解説が良い', '勘定科目の分類（資産・負債・純資産・費用・収益）がビジュアルで分かりやすく説明されていて、初心者でも混乱しません。D1対応の独自ドメインWeb版も快適です。', '2026-07-07T15:35:00Z', 1),
('rev-029', 'ケンタロウ', 5, '最高のサポート体制', 'アプリ内で分からない点があっても、キャラクターが対話形式でヒントをくれるのが新鮮です。本気で最短合格を目指すならこれ一択だと思います。', '2026-07-07T21:45:00Z', 1),
('rev-030', 'アスカ', 5, 'デザインがおしゃれでやる気出る', 'LPもアプリも、濃いネイビーのグラデーションがすごくかっこいい！安っぽいデザインのアプリが多い中、これは操作していてもプレミアム感があってモチベーションが上がります。', '2026-07-08T06:50:00Z', 1),
('rev-031', 'ビジネスマンT', 4, '効率的です', '限られた時間で成果を出したいビジネスマンに最適。無駄なページめくりや紙の準備がなく、通勤路でAIと高速で仕訳を叩き込めるのが素晴らしい。', '2026-07-08T07:30:00Z', 1),
('rev-032', 'しっぽり簿記', 5, 'Web版のドメイン移行おめでとうございます', 'Web版の新独自ドメイン移行もとてもスムーズでした。Google Play版同様に、PCの大きな画面でも集中して勉強できてとても役立っています。', '2026-07-08T08:10:00Z', 1);
